// ── MG LOGO ────────────────────────────────────────────────────────────────
const MG_LOGO_SRC = "data:image/png;base64,";

const FoxLogo = ({ size = 40 }) => (
  <div style={{
    width: size, height: size, borderRadius: size * 0.22,
    background: C.white,
    display: "flex", alignItems: "center", justifyContent: "center",
    boxShadow: "0 3px 14px rgba(0,0,0,0.18)",
    border: "2.5px solid #E5E5EA",
    overflow: "hidden",
    flexShrink: 0,
  }}>
    <img
      src={MG_LOGO_SRC}
      alt="Keçi"
      style={{ width: "90%", height: "90%", objectFit: "contain" }}
    />
  </div>
);

// ── HELPERS ────────────────────────────────────────────────────────────────
const siniflar = ["İlkokul (1-4)", "5. Sınıf", "6. Sınıf", "7. Sınıf", "8. Sınıf (LGS)",
  "9. Sınıf", "10. Sınıf", "11. Sınıf", "12. Sınıf (YKS)", "Üniversite", "Mezun"];

const renkler = ["#FF6B6B", "#4ECDC4", "#45B7D1", "#96CEB4", "#FFEAA7", "#DDA0DD", "#98D8C8", "#F7DC6F"];

const gunler = ["Pzt", "Sal", "Çar", "Per", "Cum", "Cmt", "Paz"];

function randomColor(name) {
  const idx = name.charCodeAt(0) % renkler.length;
  return renkler[idx];
}

function Avatar({ name, size = 40 }) {
  const initials = name.split(" ").slice(0, 2).map(w => w[0]).join("").toUpperCase();
  return (
    <div style={{
      width: size, height: size, borderRadius: "50%",
      background: randomColor(name), display: "flex", alignItems: "center",
      justifyContent: "center", color: C.white, fontWeight: 700,
      fontSize: size * 0.38, flexShrink: 0,
    }}>{initials}</div>
  );
}

// ── MODAL WRAPPER ──────────────────────────────────────────────────────────
function Modal({ onClose, title, children }) {
  return (
    <div style={{
      position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)",
      display: "flex", alignItems: "flex-end", justifyContent: "center",
      zIndex: 1000,
    }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{
        background: C.white, borderRadius: "20px 20px 0 0",
        width: "100%", maxWidth: 480, maxHeight: "90vh",
        overflowY: "auto", padding: "24px 20px 40px",
        animation: "slideUp 0.3s ease",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <span style={{ fontSize: 18, fontWeight: 700, color: C.dark }}>{title}</span>
          <button onClick={onClose} style={{ background: C.grayLight, border: "none", borderRadius: "50%", width: 32, height: 32, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Icon name="close" size={16} color={C.gray} />
          </button>
        </div>
        {children}
      </div>
    </div>
  );
}

// ── BUTTON ─────────────────────────────────────────────────────────────────
function Btn({ children, onClick, variant = "primary", small = false, style = {}, disabled = false }) {
  const base = {
    border: "none", borderRadius: small ? 10 : 14, cursor: disabled ? "default" : "pointer",
    fontWeight: 600, display: "flex", alignItems: "center", justifyContent: "center",
    gap: 6, transition: "opacity 0.15s",
    padding: small ? "8px 14px" : "14px 20px",
    fontSize: small ? 13 : 15,
    opacity: disabled ? 0.5 : 1,
    ...style,
  };
  const variants = {
    primary: { background: C.orange, color: C.white },
    secondary: { background: C.grayLight, color: C.dark },
    outline: { background: C.white, color: C.orange, border: `1.5px solid ${C.orange}` },
    ghost: { background: "transparent", color: C.orange },
    danger: { background: "#FFE8E8", color: C.red },
  };
  return <button onClick={disabled ? undefined : onClick} style={{ ...base, ...variants[variant] }}>{children}</button>;
}

// ── INPUT ──────────────────────────────────────────────────────────────────
function Input({ label, value, onChange, placeholder, type = "text", style = {} }) {
  return (
    <div style={{ marginBottom: 16 }}>
      {label && <div style={{ fontSize: 14, fontWeight: 600, color: C.dark, marginBottom: 6 }}>{label}</div>}
      <input
        type={type} value={value} onChange={e => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: "100%", padding: "12px 14px", borderRadius: 12,
          border: `1.5px solid ${C.grayLight}`, fontSize: 15, color: C.dark,
          background: C.bg, outline: "none", boxSizing: "border-box", ...style,
        }}
      />
    </div>
  );
}

// ── SELECT ─────────────────────────────────────────────────────────────────
function Select({ label, value, onChange, options, placeholder }) {
  return (
    <div style={{ marginBottom: 16 }}>
      {label && <div style={{ fontSize: 14, fontWeight: 600, color: C.dark, marginBottom: 6 }}>{label}</div>}
      <select value={value} onChange={e => onChange(e.target.value)} style={{
        width: "100%", padding: "12px 14px", borderRadius: 12,
        border: `1.5px solid ${C.grayLight}`, fontSize: 15, color: value ? C.dark : C.gray,
        background: C.bg, outline: "none", boxSizing: "border-box",
      }}>
        <option value="">{placeholder || "Seçiniz..."}</option>
        {options.map(o => <option key={o} value={o}>{o}</option>)}
      </select>
    </div>
  );
}

// ── CHIP SELECTOR ──────────────────────────────────────────────────────────
function ChipGroup({ options, value, onChange }) {
  return (
    <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
      {options.map(o => (
        <button key={o} onClick={() => onChange(o)} style={{
          padding: "8px 14px", borderRadius: 10, border: "none", cursor: "pointer", fontWeight: 600, fontSize: 14,
          background: value === o ? C.orange : C.grayLight,
          color: value === o ? C.white : C.dark,
        }}>{o}</button>
      ))}
    </div>
  );
}

// ── CARD ───────────────────────────────────────────────────────────────────
function Card({ children, style = {} }) {
  return (
    <div style={{
      background: C.white, borderRadius: 16, padding: 16,
      boxShadow: "0 1px 4px rgba(0,0,0,0.06)", ...style,
    }}>{children}</div>
  );
}

// ── STAT CARD ──────────────────────────────────────────────────────────────
function StatCard({ icon, label, value, sub, color = C.orange }) {
  return (
    <Card style={{ flex: 1, minWidth: 0 }}>
      <div style={{ width: 36, height: 36, borderRadius: 10, background: color + "22", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 8 }}>
        <Icon name={icon} size={18} color={color} />
      </div>
      <div style={{ fontSize: 12, color: C.gray, marginBottom: 2 }}>{label}</div>
      <div style={{ fontSize: 22, fontWeight: 800, color: C.dark }}>{value}</div>
      {sub && <div style={{ fontSize: 11, color: C.gray, marginTop: 2 }}>{sub}</div>}
    </Card>
  );
}

